  const monthList: React.ReactElement[] = [];
  const monthsShown =
    this.props.monthsShown ?? Calendar.defaultProps.monthsShown;
  const monthsToSubtract = this.props.showPreviousMonths
    ? monthsShown - 1
    : 0;
